for (i = [0:5:30])
  translate([i, 0, 0])
    cube(4);
for (angle = [0:60:300])
  rotate([0, 0, angle])
    translate([20, 0, 0])
      sphere(r=3);

for (i = [0:5])
  let (x = i * 10, y = i * i)
    translate([x, y, 0])
      cube(5);

module box(size) {
  assert(size > 0, "Size must be positive");
  cube(size);
}

module rounded_box(w, h, d, r=2) {
  minkowski() {
    cube([w-2*r, h-2*r, d-2*r], center=true);
    sphere(r=r);
  }
}
rounded_box(20, 10, 5);

module colorize() {
  color("red") children(0);
  color("blue") children(1);
}
colorize() {
  cube(10);
  sphere(r=5);
}

difference() {
  cube(20, center=true);
  # sphere(r=13); // highlighted in red to see the cut
}

module foo(x) {
  size = is_undef(x) ? 10 : x;
  cube(size);
}
